import os
import subprocess

def backup_directory(dir_path, compression):
    if not os.path.exists(dir_path):
        print("Directory does not exist.")
        return
    
    dir_name = os.path.basename(os.path.normpath(dir_path))
    backup_file = f"{dir_name}.{compression}"
    
    if compression == "tar.gz":
        subprocess.run(['tar', '-czvf', backup_file, dir_name], cwd=os.path.dirname(dir_path))
        
    elif compression == "tar.bz2":
        subprocess.run(['tar', '-cjvf', backup_file, dir_name], cwd=os.path.dirname(dir_path))
        
    elif compression == "zip":
        subprocess.run(['zip', '-r', backup_file, dir_name], cwd=os.path.dirname(dir_path))
    
    else:
        print("Unsupported compression format.")
        return
    
    print(f"Backup created successfully: {backup_file}")